        require(
            balances[msg.sender] >= amount,
            "Insufficient balance"
        );
        /*
        EFFECTS
        */
        balances[msg.sender] -= amount;
        /*
        INTERACTIONS
        */
        (bool succes, ) = 
        msg.sender.call{value: amount}("");
        require(
            succes,
            "Transfer failed"
        );
    }
    /*
    =========================================
    VIEW BALANCE
    ==========================================
