require(
    logic != address(0),
    "Invalid logic"
);
Patched Code
*/
contract LogicContract {

    uint256 public num;
    address public sender;

    function set(uint256 _num)
        external
    {
        num = _num;
        sender = msg.sender;
    }
}

contract ProxyContract {

    address public logic;

    constructor(address _logic) {
        require(
            _logic != address(0),
            "Invalid logic"
        );
        logic = _logic;
